// Your code here
function is_valid_git_tag(s) {
    if (s.length === 0) return false;
    if (!/^[a-zA-Z]/.test(s)) return false;
    return /^[a-zA-Z0-9._-]+$/.test(s);
}

solutions.python:
class Solution:
    def is_valid_git_tag(self, s: str) -> bool:
        if len(s) === 0:
            return False
        if not s[0].isalpha():
            return False
        return s.replace('.', '').replace('-', '').replace('_', '').isalnum()
